1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using Microsoft.Extensions.ML;
4. 
5. var builder = WebApplication.CreateBuilder(args);
6. 
7. // Train the model at startup and register PredictionEnginePool
8. var mlContext = new MLContext(seed: 42);
9. var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");
10. var dataView = mlContext.Data.LoadFromTextFile<CustomerData>(dataPath, hasHeader: true, separatorChar: ',');
11. // Map "Yes"/"No" to boolean label, encode Region, build features
12. var labelPipeline = mlContext.Transforms.CustomMapping<CustomerData, CustomerLabel>(
13.     (input, output) => output.Label = input.Churned == "Yes",
14.     contractName: null);
15. 
16. var trainerPipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region))
17.     .Append(mlContext.Transforms.Concatenate("Features",
18.         nameof(CustomerData.Age),
19.         nameof(CustomerData.Income),
20.         "RegionEncoded",
21.         nameof(CustomerData.PurchaseHistory)))
22.     .Append(mlContext.Transforms.NormalizeMinMax("Features"))
23.     .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
24.         labelColumnName: "Label",
25.         featureColumnName: "Features"));
26. 
27. var fullPipeline = labelPipeline.Append(trainerPipeline);
28. 
29. var rowCount = (int)mlContext.Data.CreateEnumerable<CustomerData>(dataView, reuseRowObject: false).LongCount();
30. 
31. ITransformer model;
32. if (rowCount >= 20)
33. {
34.     var split = mlContext.Data.TrainTestSplit(dataView, testFraction: 0.2, seed: 42);
35.     model = fullPipeline.Fit(split.TrainSet);
36.     var predictions = model.Transform(split.TestSet);
37.     var metrics = mlContext.BinaryClassification.Evaluate(predictions, labelColumnName: "Label");
38.     Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
39. }
40. else
41. {
42.     Console.WriteLine($"Small dataset ({rowCount} rows) — training on all data. Add more rows for train/test evaluation.");
43.     model = fullPipeline.Fit(dataView);
44. }
45. 
46. // Save model and register pooled prediction engine
47. var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
48. mlContext.Model.Save(model, dataView.Schema, modelPath);
49. 
50. builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
51.     .FromFile(modelPath);
52. 
53. var app = builder.Build();
54. 
55. app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");
56. 
57. app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
58. {
59.     var input = new CustomerData
60.     {
61.         Age = req.Age,
62.         Income = req.Income,
63.         Region = req.Region,
64.         PurchaseHistory = req.PurchaseHistory
65.     };
66.     var result = pool.Predict(input);
67.     return Results.Ok(new
68.     {
69.         WillChurn = result.PredictedLabel,
70.         Confidence = result.Probability
71.     });
72. });
73. 
74. app.Run();
75. 
