78. public class CustomerData
79. {
80.     [LoadColumn(0)] public float Age { get; set; }
81.     [LoadColumn(1)] public float Income { get; set; }
82.     [LoadColumn(2)] public string Region { get; set; } = "";
83.     [LoadColumn(3)] public float PurchaseHistory { get; set; }
84.     [LoadColumn(4)] public string Churned { get; set; } = "";
85. }
